INSERT INTO exercises (name, muscle_groups, equipment, difficulty, description, is_custom) VALUES

-- ─── Спина (дополнение) ────────────────────────────────────────────────────────
('Тяга горизонтального блока', ARRAY['широчайшие', 'трапеция', 'бицепс', 'ромбовидные'], 'блок', 'beginner', 'Сидя тянуть горизонтальную рукоять к животу. Спина прямая, лопатки сводить в конце движения.', false),
('Подтягивания обратным хватом', ARRAY['широчайшие', 'бицепс'], 'турник', 'intermediate', 'Хват снизу (супинация). Лучше изолирует бицепс, амплитуда шире чем при прямом хвате.', false),
('Тяга верхнего блока узким хватом', ARRAY['широчайшие', 'бицепс', 'ромбовидные'], 'блок', 'beginner', 'Тянуть рукоять параллельным или обратным хватом к верхней части груди. Акцент на нижние широчайшие.', false),
('Тяга к лицу на блоке', ARRAY['задняя дельта', 'ромбовидные', 'трапеция'], 'блок', 'beginner', 'Тянуть рукоять горизонтального блока к лицу широким хватом. Профилактика травм плеча, укрепление задней дельты.', false),
('Тяга гантелей к поясу лёжа', ARRAY['широчайшие', 'трапеция', 'ромбовидные'], 'гантели', 'beginner', 'Лёжа лицом вниз на наклонной скамье, тянуть гантели к пояснице. Изолирует спину без нагрузки на поясницу.', false),

-- ─── Грудь (дополнение) ────────────────────────────────────────────────────────
('Сведение рук в тренажёре (Баттерфляй)', ARRAY['грудь'], 'тренажёр', 'beginner', 'Сидя в тренажёре сводить рукояти перед грудью. Чистая изоляция грудных мышц.', false),
('Жим гантелей на обратнонаклонной скамье', ARRAY['нижняя грудь', 'трицепс'], 'гантели', 'intermediate', 'Скамья под углом вниз 15–30°. Акцент на нижний пучок грудных мышц.', false),
('Отжимания с широкой постановкой рук', ARRAY['грудь', 'передняя дельта'], 'без оборудования', 'beginner', 'Руки шире плеч — акцент смещается на внешнюю часть грудных.', false),
('Алмазные отжимания', ARRAY['трицепс', 'грудь'], 'без оборудования', 'intermediate', 'Руки сложены в форме ромба под грудью. Основная нагрузка на трицепс и внутреннюю часть груди.', false),

-- ─── Плечи (дополнение) ────────────────────────────────────────────────────────
('Разводка гантелей в наклоне', ARRAY['задняя дельта', 'ромбовидные'], 'гантели', 'beginner', 'В наклоне вперёд поднимать гантели в стороны. Акцент на задний пучок дельты и ромбовидные.', false),
('Жим в тренажёре для плеч', ARRAY['передняя дельта', 'средняя дельта', 'трицепс'], 'тренажёр', 'beginner', 'Жим в плечевом тренажёре. Удобен для новичков — задаёт траекторию движения.', false),
('Подъём гантелей в стороны сидя', ARRAY['средняя дельта'], 'гантели', 'beginner', 'Разводка в стороны сидя — исключает раскачку корпуса, чистая изоляция средней дельты.', false),

-- ─── Ноги (дополнение) ────────────────────────────────────────────────────────
('Приседания без оборудования', ARRAY['квадрицепс', 'ягодицы', 'бицепс бедра'], 'без оборудования', 'beginner', 'Классические приседания без веса. Базовое движение для новичков и разминки.', false),
('Выпады назад', ARRAY['квадрицепс', 'ягодицы', 'бицепс бедра'], 'без оборудования', 'beginner', 'Шаг назад с опусканием колена к полу. Меньше нагрузки на колено чем при выпадах вперёд.', false),
('Выпады назад с гантелями', ARRAY['квадрицепс', 'ягодицы', 'бицепс бедра'], 'гантели', 'beginner', 'Выпады назад с отягощением в руках для увеличения нагрузки.', false),
('Выпады со штангой', ARRAY['квадрицепс', 'ягодицы', 'бицепс бедра'], 'штанга', 'intermediate', 'Штанга на трапеции, поочерёдные выпады вперёд. Максимальная нагрузка на ноги.', false),
('Зашагивания на платформу', ARRAY['квадрицепс', 'ягодицы'], 'без оборудования', 'beginner', 'Поочерёдно ставить ногу на возвышение и подниматься. Можно с гантелями.', false),
('Зашагивания на платформу с гантелями', ARRAY['квадрицепс', 'ягодицы'], 'гантели', 'intermediate', 'Зашагивания с отягощением для усиления нагрузки на квадрицепс и ягодицы.', false),
('Сведение ног в тренажёре', ARRAY['внутренняя поверхность бедра', 'приводящие'], 'тренажёр', 'beginner', 'Сидя сводить ноги в тренажёре. Изолирует приводящие мышцы бедра.', false),
('Разведение ног в тренажёре', ARRAY['отводящие', 'средняя ягодичная'], 'тренажёр', 'beginner', 'Сидя разводить ноги в тренажёре. Укрепляет отводящие мышцы и среднюю ягодичную.', false),
('Гакк-приседания', ARRAY['квадрицепс', 'ягодицы'], 'тренажёр', 'intermediate', 'Приседания в тренажёре с упором спины. Акцент на квадрицепс, меньше нагрузки на поясницу.', false),
('Ягодичный мостик на одной ноге', ARRAY['ягодицы', 'бицепс бедра', 'кор'], 'без оборудования', 'intermediate', 'Лёжа на спине, одна нога согнута, вторая вытянута. Поднимать таз за счёт одной ноги.', false),
('Приседания на одной ноге (пистолет)', ARRAY['квадрицепс', 'ягодицы', 'кор'], 'без оборудования', 'advanced', 'Приседание на одной ноге с вытянутой второй перед собой. Требует баланса и силы.', false),
('Становая тяга Сумо', ARRAY['внутренняя поверхность бедра', 'ягодицы', 'квадрицепс', 'поясница'], 'штанга', 'intermediate', 'Широкая стойка, носки развёрнуты. Акцент на приводящие и ягодицы.', false),

